const synthetics = require('Synthetics');
const log = require('SyntheticsLogger');

const pageLoadBlueprint = async function () {
    // 1. Define URL
    const HOSTNAME = process.env.API_HOSTNAME;
    const PATH = process.env.API_PATH;
    const URL = `https://${HOSTNAME}${PATH}`;

    log.info('Checking URL: ${URL}');

    let page = await synthetics.getPage();
    await page.setViewport({ width: 1920, height: 1080 });

    const client = await page.target().createCDPSession();


    // 2. Load the Page (AND SAVE IT TO 'const response')
    // This is the line that was likely broken
    const response = await page.goto(URL, {waitUntil: 'domcontentloaded', timeout: 30000});
    
    // 3. Check if response exists
    if (!response) { 
        throw "Failed to load page! No response received."; 
    }

    // 4. Check Status (This is where your error was happening)
    const status = response.status();
    log.info(`Response Status: ${status}`);
    
    if (status < 200 || status > 299) {
        throw `Failed to load page! Status Code: ${status}`;
    }
    
    await synthetics.takeScreenshot('loaded', 'loaded');
};

exports.handler = async () => {
    return await pageLoadBlueprint();
};
